def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate a personalized profile banner using the provided template and user information.

    Uses a sandboxed Jinja2 environment to prevent Server-Side Template Injection (SSTI)
    while still supporting Jinja2 template syntax for placeholders.

    Args:
        banner_template: A user-provided banner template string with {{ placeholder }} syntax
        user_info: Dictionary containing user profile information

    Returns:
        Rendered HTML banner string with placeholders replaced by user data
    """
    env = StrictSandboxedEnvironment()

    # Build safe context with only whitelisted keys
    safe_context = {}
    for key in ALLOWED_PLACEHOLDERS:
        if key in user_info:
            safe_context[key] = str(user_info[key])

    # Also provide a 'user' object for {{ user.name }} style access
    safe_context['user'] = SafeUserDict(user_info)

    try:
        template = env.from_string(banner_template)
        result = template.render(**safe_context)
    except Exception:
